// src/services/AuthService.js
import AuthRepository from '../repositories/AuthRepository';
import UserRepository from '../repositories/UserRepository';

const AuthService = {
  async login(email, password) {
    // Check if email exists in profiles
    const emailExists = await AuthRepository.emailExists(email);

    if (!emailExists) {
      return { redirect: 'register', message: 'Email não encontrado. Vamos criar sua conta!' };
    }

    // Try to login
    const data = await AuthRepository.login(email, password);
    return { success: true, data };
  },

  async register(email, password, name, role = 'standard') {
    // Create auth user
    const authData = await AuthRepository.register(email, password);

    if (!authData.user) {
      throw new Error('Erro ao criar usuário na autenticação.');
    }

    await UserRepository.create({
      id: authData.user.id,
      email,
      name,
      role,
      created_at: new Date().toISOString()
    });

    return { success: true };
  },

  async logout() {
    return await AuthRepository.logout();
  },

  async getCurrentSession() {
    return await AuthRepository.getCurrentSession();
  },

  onAuthStateChange(callback) {
    return AuthRepository.onAuthStateChange(callback);
  }
};

export default AuthService;
